			s.clear();

			model.setYear( new Date() );
			manufacturer = s.get( Manufacturer.class, manufacturer.getId() );
			@SuppressWarnings("unchecked")
			List<Model> cars = s.getNamedQuery( "allModelsPerManufacturer" )
